API_name: nchu_cross_program_search_by_time
Description:
{
  "description": "依上課時間查詢學分學程課程（星期幾、第幾節）。",
  "required_parameters": [
    {
      "name": "weekday",
      "type": "STRING",
      "description": "星期（1=一, 2=二, ..., 7=日）"
    }
  ],
  "optional_parameters": [
    {
      "name": "period",
      "type": "STRING",
      "description": "節次（1-9 日間, A-D 夜間）",
      "default": null
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "學年期代碼",
      "default": null
    }
  ]
}

